import { getTicks } from '@visx/scale';
import type { ScaleLinear } from 'd3-scale';

import { DivAxisWrapper } from './DivAxisWrapper.js';
import {
  TickPrimitiveValue,
  TickValueFormatter,
} from '../../../types/tick-value.js';
import { getTickValues } from '../../../utils/format-value.js';
import { getHorizontalNumTicks } from '../../../utils/ticks.js';
import { AxisTableHeader } from '../AxisTableHeader.js';
import { axisFontProps } from '../constants.js';
import { getTickLabelPropsForGanttAxis } from '../utils/get-tick-label-props.js';

/**
 * @internal
 */
export interface ValueTableHeaderAxisProps {
  scale: ScaleLinear<number, number>;
  containerWidth: number;
  containerHeight: number;
  formatter?: TickValueFormatter;
  stroke?: string;
  min?: number;
  max?: number;
}

/**
 * @internal
 */
export const ValueTableHeaderAxis = (props: ValueTableHeaderAxisProps) => {
  const {
    scale,
    containerWidth,
    containerHeight,
    formatter,
    stroke,
    min,
    max,
  } = props;
  const numTicks = getHorizontalNumTicks(containerWidth);
  const ticks = getTicks(scale, numTicks) as TickPrimitiveValue[];
  const tickValues = getTickValues(ticks, formatter);
  const tickFormat = (_: unknown, index: number) => tickValues[index];

  return (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={tickValues}
      isTickVertical
    >
      <AxisTableHeader
        role="graphics-symbol"
        aria-label="value axis tableheader"
        scale={scale}
        containerSize={containerWidth}
        height={containerHeight}
        numTicks={numTicks}
        tickValues={ticks}
        tickLabelProps={getTickLabelPropsForGanttAxis(min, max)}
        tickFormat={tickFormat}
        stroke={stroke}
      />
    </DivAxisWrapper>
  );
};

ValueTableHeaderAxis['displayName'] = 'ValueTableHeaderAxis';
